function useJoinForm() {
  const [formState, setFormState] = reactExports.useState("idle");
  const { actor } = useActor(createActor);
  const form = useForm({
    defaultValues: {
      nom: "",
      email: "",
      telephone: "",
      ville: "",
      message: ""
    }
  });
  const onSubmit = async (data) => {
    setFormState("submitting");
    try {
      if (!actor) throw new Error("Actor not ready");
      await actor.submitJoinForm(
        data.nom,
        data.email,
        data.telephone,
        data.ville
      );
      setFormState("success");
      form.reset();
    } catch {
      setFormState("error");
    }
  };
  const reset = () => {
    setFormState("idle");
    form.reset();
  };
  return { form, onSubmit: form.handleSubmit(onSubmit), formState, reset };
}
